public class ReverseAWord {

public static void main(String[] args) {

        String str="This is India";
        String reverseredStr= reverse(str);
        System.out.println(reverseredStr);


    }

    public static String reverse(String originalStr){
        char strChar[] = originalStr.toCharArray();
        int len = originalStr.length();
        int start= 0;
        int end = len-1;
        while(start<end){
            char temp = strChar[start];
            strChar[start]=strChar[end];
            strChar[end]=temp;
            start++;
            end--;

        }

        return new String(strChar);

    }
}

